const articles = $input.all();
const grouped = {};
for (const item of articles) {
  const cat = item.json.category || 'general';
  if (!grouped[cat]) grouped[cat] = [];
  grouped[cat].push(item.json);
}
let md = '# AI News Weekly Digest\n\n';
for (const [cat, items] of Object.entries(grouped)) {
  md += `### ${cat.toUpperCase()}\n\n`;
  for (const a of items) {
    md += `- **[${a.title}](${a.url})**\n  ${a.summary?.slice(0,200) || ''}\n  *${a.source}*\n\n`;
  }
}
return [{ json: { markdown: md } }];
